def make_html(title,books):
    data=json.dumps(books,ensure_ascii=False,separators=(',',':')).replace('</','<\\/')
    return HTML_TEMPLATE.replace('%%TITLE%%',html.escape(title)).replace('%%BOOKS%%',data)
def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--title',default='–€–Ψ―è PDF-–±―•–±–Μ―•–Ψ―²–Β–Κ–Α'); ap.add_argument('--author',default='–ù–Β–≤―•–¥–Ψ–Φ–Η–Ι –Α–≤―²–Ψ―Ä'); ap.add_argument('--category',default='–ë–Β–Ζ –Κ–Α―²–Β–≥–Ψ―Ä―•―½'); ap.add_argument('--cover-zoom',type=float,default=2.2); args=ap.parse_args()
    books,covers=build_books(args.author,args.category,args.cover_zoom)
    OUT.write_text(make_html(args.title,books),encoding='utf-8')
    print(f'–™–Ψ―²–Ψ–≤–Ψ. PDF: {len(books)}. –û–±–Κ–Μ–Α–¥–Η–Ϋ–Ψ–Κ: {covers}. –Λ–Α–Ι–Μ: index.html')
if __name__=='__main__': main()
